mapper.select:
select CASE WHEN COUNT(*) = 0 THEN 1 ELSE MAX(reg_seq)+1 END AS reg_seq
from   tb_move_stock_mst
where  move_reg_date = #{moveRegDate}

select CONCAT(CONVERT(varchar(10), a.move_stock_date, 23), ' - ', a.seq) AS moveStockDateSeq ,d.storage_name as src_storage_name ,e.storage_name as tar_storage_name ,CASE WHEN COUNT(DISTINCT b.item_cd) = 1 THEN MIN(c.item_name) ELSE CONCAT(MIN(c.item_name), ' 외 ', COUNT(DISTINCT b.item_cd) - 1, '건') END AS item_name ,sum(b.qty) as qty , a.memo ,f.member_nm as manager_name ,a.move_status ,a.move_stock_id from tb_move_stock_mst a left join tb_move_req_item b on a.move_stock_id = b.move_stock_id left join tb_item_mst c on c.item_cd = b.item_cd inner join tb_storage_mst d on d.storage_cd = a.src_storage_cd inner join tb_storage_mst e on e.storage_cd = a.tar_storage_cd inner join tb_users f on f.user_id = a.manager_id WHERE a.move_stock_date BETWEEN #{strDate} AND #{endDate} and a.type_cd ='Q'
AND a.area_cd = #{areaCd}
AND a.move_status = #{moveStatus}
AND a.src_storage_cd = #{srcStorageCd}
AND a.tar_storage_cd = #{tarStorageCd}
AND c.item_cd LIKE '%' + #{itemCd} + '%'
AND c.item_name LIKE '%' + #{itemName} + '%'
GROUP BY a.move_stock_date, a.seq, d.storage_name, e.storage_name, f.member_nm ,a.move_status,a.move_stock_id, a.memo ORDER BY a.move_stock_date desc, a.seq desc

mapper.update:
update tb_move_stock_mst
set    move_reg_date    = #{moveRegDate}
      ,reg_seq          = #{regSeq}
      ,move_manager_id  = #{moveManagerId}
      ,confirmer_id     = #{confirmerId}
      ,etc              = #{etc}
      ,move_status      = #{moveStatus}
      ,confirm_status   = #{confirmStatus}
      ,upd_id           = #{userId}
      ,upd_dt           = getdate()
where  move_stock_id    = #{moveStockId}

UPDATE tb_move_stock_item
SET item_type_cd = #{itemTypeCd}
  , item_cd      = #{itemCd}
  , test_no      = #{testNo}
  , qty          = #{qty}
  , lot_no       = #{lotNo}
  , upd_id       = #{userId}
  , upd_dt       = GETDATE()
WHERE move_stock_item_id = #{moveStockItemId}
